func (s *Server) handleCreateUser(w http.ResponseWriter, r *http.Request) {
	var req CreateUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.badRequest(w, "Invalid request body")
		return
	}
	if req.Email == "" {
		s.badRequest(w, "Email is required")
		return
	}
	if !isValidEmail(req.Email) {
		s.badRequest(w, "Invalid email format")
		return
	}
	if req.Name == "" {
		s.badRequest(w, "Name is required")
		return
	}
	if req.LocationPreference != "" && !isValidLocation(req.LocationPreference) {
		s.badRequest(w, "Invalid location_preference value")
		return
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	for _, u := range s.users {
		if u.Email == req.Email {
			s.badRequest(w, "Email already exists")
			return
		}
	}

	nowStr := now()
	user := &User{
		ID:                  uuid.New().String(),
		Email:               req.Email,
		Name:                req.Name,
		Title:               req.Title,
		TargetSalaryMin:     req.TargetSalaryMin,
		TargetSalaryMax:     req.TargetSalaryMax,
		LocationPreference:  req.LocationPreference,
		Skills:              req.Skills,
		ExperienceYears:     req.ExperienceYears,
		IndustryPreferences: req.IndustryPreferences,
		Persona:             classifyPersona(req),
		CreatedAt:           nowStr,
		UpdatedAt:           nowStr,
	}
	s.users[user.ID] = user
	s.json(w, http.StatusCreated, user)
}

func classifyPersona(req CreateUserRequest) string {
	skills := append([]string{}, req.Skills...)
	if req.IndustryPreferences != nil {
		skills = append(skills, req.IndustryPreferences...)
	}
	text := strings.ToLower(strings.Join(skills, " "))
	if strings.Contains(text, "startup") || strings.Contains(text, "founder") ||
		strings.Contains(text, "fix") || strings.Contains(text, "turnaround") {
		return "Startup/Fixer"
	}
	if strings.Contains(text, "sales") || strings.Contains(text, "revenue") ||
		strings.Contains(text, "growth") {
		return "Sales"
	}
	if strings.Contains(text, "technical") || strings.Contains(text, "engineering") ||
		strings.Contains(text, "machine learning") || strings.Contains(text, "data") {
		return "Technical"
	}
	if strings.Contains(text, "manage") || strings.Contains(text, "lead") ||
		strings.Contains(text, "director") || strings.Contains(text, "vp") {
		return "Management"
	}
	return "Creative"
}

func (s *Server) handleUserByID(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimPrefix(r.URL.Path, "/v1/users/")
	if id == "" {
		s.notFound(w)
		return
	}

	switch r.Method {
	case http.MethodGet:
		s.mu.RLock()
		user, ok := s.users[id]
		s.mu.RUnlock()
		if !ok {
			s.notFound(w)
			return
		}
		s.json(w, http.StatusOK, user)

	case http.MethodPut:
		var req UpdateUserRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			s.badRequest(w, "Invalid request body")
			return
		}
		if req.Email != nil && !isValidEmail(*req.Email) {
			s.badRequest(w, "Invalid email format")
			return
		}
		if req.LocationPreference != nil && !isValidLocation(*req.LocationPreference) {
			s.badRequest(w, "Invalid location_preference value")
			return
		}

		s.mu.Lock()
		user, ok := s.users[id]
		if !ok {
			s.mu.Unlock()
			s.notFound(w)
			return
		}
		if req.Email != nil {
			user.Email = *req.Email
		}
		if req.Name != nil {
			user.Name = *req.Name
		}
		if req.Title != nil {
			user.Title = *req.Title
		}
		if req.TargetSalaryMin != nil {
			user.TargetSalaryMin = req.TargetSalaryMin
		}
		if req.TargetSalaryMax != nil {
			user.TargetSalaryMax = req.TargetSalaryMax
		}
		if req.LocationPreference != nil {
			user.LocationPreference = *req.LocationPreference
		}
		if req.Skills != nil {
			user.Skills = req.Skills
		}
		if req.ExperienceYears != nil {
			user.ExperienceYears = req.ExperienceYears
		}
		if req.IndustryPreferences != nil {
			user.IndustryPreferences = req.IndustryPreferences
		}
		user.UpdatedAt = now()
		s.mu.Unlock()
		s.json(w, http.StatusOK, user)

	default:
		s.methodNotAllowed(w)
	}
}

