func (s *Server) handleJobByID(w http.ResponseWriter, r *http.Request) {
	path := strings.TrimPrefix(r.URL.Path, "/v1/jobs/")
	parts := strings.SplitN(path, "/", 2)
	id := parts[0]
	if id == "" {
		s.notFound(w)
		return
	}

	switch r.Method {
	case http.MethodGet:
		s.mu.RLock()
		job, ok := s.jobs[id]
		s.mu.RUnlock()
		if !ok {
			s.notFound(w)
			return
		}
		s.json(w, http.StatusOK, job)

	case http.MethodPut:
		var req UpdateJobRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			s.badRequest(w, "Invalid request body")
			return
		}
		if req.LocationType != nil && !isValidLocation(*req.LocationType) {
			s.badRequest(w, "Invalid location_type value")
			return
		}

		s.mu.Lock()
		job, ok := s.jobs[id]
		if !ok {
			s.mu.Unlock()
			s.notFound(w)
			return
		}
		if req.Title != nil {
			job.Title = *req.Title
		}
		if req.Company != nil {
			job.Company = *req.Company
		}
		if req.Location != nil {
			job.Location = *req.Location
		}
		if req.LocationType != nil {
			job.LocationType = *req.LocationType
		}
		if req.SalaryMin != nil {
			job.SalaryMin = req.SalaryMin
		}
		if req.SalaryMax != nil {
			job.SalaryMax = req.SalaryMax
		}
		if req.Description != nil {
			job.Description = *req.Description
		}
		if req.URL != nil {
			job.URL = *req.URL
		}
		if req.Status != nil {
			job.Status = *req.Status
		}
		if req.Notes != nil {
			job.Notes = *req.Notes
		}
		job.UpdatedAt = now()
		s.mu.Unlock()
		s.json(w, http.StatusOK, job)

	case http.MethodPatch:
		if len(parts) > 1 && parts[1] == "status" {
			var req UpdateStatusRequest
			if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
				s.badRequest(w, "Invalid request body")
				return
			}
			if !isValidJobStatus(req.Status) {
				s.badRequest(w, "Invalid status value")
				return
			}
			s.mu.Lock()
			job, ok := s.jobs[id]
			if !ok {
				s.mu.Unlock()
				s.notFound(w)
				return
			}
			job.Status = req.Status
			job.UpdatedAt = now()
			s.mu.Unlock()
			s.json(w, http.StatusOK, job)
			return
		}
		s.notFound(w)

	case http.MethodDelete:
		s.mu.Lock()
		if _, ok := s.jobs[id]; !ok {
			s.mu.Unlock()
			s.notFound(w)
			return
		}
		delete(s.jobs, id)
		s.mu.Unlock()
		w.WriteHeader(http.StatusNoContent)

	default:
		s.methodNotAllowed(w)
	}
}

func (s *Server) handleListJobs(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	status := r.URL.Query().Get("status")
	locationType := r.URL.Query().Get("location_type")
	sortBy := r.URL.Query().Get("sort")
	limit, offset := 20, 0

	if l := r.URL.Query().Get("limit"); l != "" {
		fmt.Sscanf(l, "%d", &limit)
	}
	if limit > 100 {
		limit = 100
	}
	if o := r.URL.Query().Get("offset"); o != "" {
		fmt.Sscanf(o, "%d", &offset)
	}

	s.mu.RLock()
	var jobs []*Job
	for _, job := range s.jobs {
		if userID != "" && job.UserID != userID {
			continue
		}
		if status != "" && job.Status != status {
			continue
		}
		if locationType != "" && job.LocationType != locationType {
			continue
		}
		jobs = append(jobs, job)
	}
	s.mu.RUnlock()

	sort.Slice(jobs, func(i, j int) bool {
		switch sortBy {
		case "discovered_at_desc":
			return jobs[i].DiscoveredAt > jobs[j].DiscoveredAt
		case "discovered_at_asc":
			return jobs[i].DiscoveredAt < jobs[j].DiscoveredAt
		case "salary_desc":
			si, sj := 0, 0
			if jobs[i].SalaryMax != nil {
				si = *jobs[i].SalaryMax
			}
			if jobs[j].SalaryMax != nil {
				sj = *jobs[j].SalaryMax
			}
			return si > sj
		default: // fit_score_desc (default)
			si, sj := 0.0, 0.0
			if jobs[i].FitScore != nil {
				si = *jobs[i].FitScore
			}
			if jobs[j].FitScore != nil {
				sj = *jobs[j].FitScore
			}
			return si > sj
		}
	})

	total := len(jobs)
	if offset >= len(jobs) {
		jobs = []*Job{}
	} else {
		end := offset + limit
		if end > len(jobs) {
			end = len(jobs)
		}
		jobs = jobs[offset:end]
	}

	s.json(w, http.StatusOK, map[string]interface{}{
		"jobs":  jobs,
		"total": total,
	})
}

