func (s *Server) handleScore(w http.ResponseWriter, r *http.Request) {
	var req ScoreRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.badRequest(w, "Invalid request body")
		return
	}
	if req.UserID == "" || req.JobID == "" {
		s.badRequest(w, "user_id and job_id are required")
		return
	}

	s.mu.Lock()
	user, userOk := s.users[req.UserID]
	job, jobOk := s.jobs[req.JobID]
	if !userOk || !jobOk {
		s.mu.Unlock()
		s.notFound(w)
		return
	}

	sm := s.computeSkillMatch(user, job)
	sf := s.computeSalaryFit(user, job)
	lf := s.computeLocationFit(user, job)
	sf2 := s.computeSeniorityFit(user, job)
	indf := s.computeIndustryFit(user, job)
	overall := sm*0.35 + sf*0.20 + lf*0.15 + sf2*0.15 + indf*0.15

	scoreKey := req.UserID + ":" + req.JobID
	result := &ScoreResult{
		ID:           uuid.New().String(),
		JobID:        req.JobID,
		UserID:       req.UserID,
		OverallScore: overall,
		SkillMatch:   sm,
		SalaryFit:    sf,
		LocationFit:  lf,
		SeniorityFit: sf2,
		IndustryFit:  indf,
		Reasoning:    fmt.Sprintf("skill=%.0f%% salary=%.0f%% location=%.0f%% seniority=%.0f%% industry=%.0f%%", sm, sf, lf, sf2, indf),
		CreatedAt:    now(),
	}
	s.scores[scoreKey] = result

	fs := overall
	job.FitScore = &fs
	job.UpdatedAt = now()
	s.mu.Unlock()

	s.json(w, http.StatusOK, result)
}

func (s *Server) computeSkillMatch(user *User, job *Job) float64 {
	if len(user.Skills) == 0 || job.Description == "" {
		return 50.0
	}
	desc := job.Title + " " + job.Description + " " + job.Company
	matches := countKeywordMatches(desc, user.Skills)
	count := len(user.Skills)
	score := float64(matches) / float64(count) * 100.0
	if score > 100 {
		score = 100
	}
	return score
}

func (s *Server) computeSalaryFit(user *User, job *Job) float64 {
	if user.TargetSalaryMin == nil || user.TargetSalaryMax == nil || job.SalaryMin == nil || job.SalaryMax == nil {
		return 50.0
	}
	if *job.SalaryMin <= *user.TargetSalaryMax && *job.SalaryMax >= *user.TargetSalaryMin {
		return 100.0
	}
	gap := 0
	if *job.SalaryMax < *user.TargetSalaryMin {
		gap = *user.TargetSalaryMin - *job.SalaryMax
	} else if *job.SalaryMin > *user.TargetSalaryMax {
		gap = *job.SalaryMin - *user.TargetSalaryMax
	}
	rangeSize := *user.TargetSalaryMax - *user.TargetSalaryMin
	if rangeSize <= 0 {
		rangeSize = 1
	}
	penalty := float64(gap) / float64(rangeSize) * 100.0
	if penalty > 100 {
		penalty = 100
	}
	return 100.0 - penalty
}

func (s *Server) computeLocationFit(user *User, job *Job) float64 {
	pref, loc := user.LocationPreference, job.LocationType
	if pref == "" || loc == "" {
		return 75.0
	}
	if pref == "any" || loc == "any" {
		return 100.0
	}
	if pref == loc || loc == "remote" {
		return 100.0
	}
	if pref == "remote" && loc == "hybrid" {
		return 50.0
	}
	if pref == "remote" && loc == "onsite" {
		return 25.0
	}
	if pref == "hybrid" && loc == "onsite" {
		return 50.0
	}
	return 75.0
}

func (s *Server) computeSeniorityFit(user *User, job *Job) float64 {
	if user.ExperienceYears == nil {
		return 50.0
	}
	exp := *user.ExperienceYears
	title := strings.ToLower(job.Title)

	high := []string{"chief", "head", "vp", "vice president", "director", "svp", "executive", "officer", "president"}
	mid := []string{"senior", "sr.", "sr ", "lead", "principal", "staff"}
	low := []string{"junior", "jr.", "jr ", "entry", "associate", "mid", "intern"}

	score := 50.0
	for _, kw := range high {
		if strings.Contains(title, kw) {
			score = 100.0
			break
		}
	}
	for _, kw := range mid {
		if strings.Contains(title, kw) {
			score = 75.0
			break
		}
	}
	for _, kw := range low {
		if strings.Contains(title, kw) {
			score = 40.0
			break
		}
	}
	if score >= 80 && exp < 5 {
		score = 40.0
	} else if score >= 60 && exp < 3 {
		score = 40.0
	}
	return score
}

func (s *Server) computeIndustryFit(user *User, job *Job) float64 {
	if len(user.IndustryPreferences) == 0 {
		return 50.0
	}
	desc := job.Description + " " + job.Company
	matches := 0
	for _, ind := range user.IndustryPreferences {
		if strings.Contains(strings.ToLower(desc), strings.ToLower(ind)) {
			matches++
		}
	}
	count := len(user.IndustryPreferences)
	score := float64(matches) / float64(count) * 100.0
	if score > 100 {
		score = 100
	}
	return score
}

func (s *Server) handleBulkScore(w http.ResponseWriter, r *http.Request) {
	var req BulkScoreRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.badRequest(w, "Invalid request body")
		return
	}
	if req.UserID == "" {
		s.badRequest(w, "user_id is required")
		return
	}

	s.mu.Lock()
	user, ok := s.users[req.UserID]
	if !ok {
		s.mu.Unlock()
		s.notFound(w)
		return
	}

	var results []*ScoreResult
	for _, job := range s.jobs {
		if job.UserID != req.UserID {
			continue
		}
		sm := s.computeSkillMatch(user, job)
		sf := s.computeSalaryFit(user, job)
		lf := s.computeLocationFit(user, job)
		sf2 := s.computeSeniorityFit(user, job)
		indf := s.computeIndustryFit(user, job)
		overall := sm*0.35 + sf*0.20 + lf*0.15 + sf2*0.15 + indf*0.15

		scoreKey := req.UserID + ":" + job.ID
		result := &ScoreResult{
			ID:           uuid.New().String(),
			JobID:        job.ID,
			UserID:       req.UserID,
			OverallScore: overall,
			SkillMatch:   sm,
			SalaryFit:    sf,
			LocationFit:  lf,
			SeniorityFit: sf2,
			IndustryFit:  indf,
			CreatedAt:    now(),
		}
		s.scores[scoreKey] = result
		fs := overall
		job.FitScore = &fs
		job.UpdatedAt = now()
		results = append(results, result)
	}
	s.mu.Unlock()

	s.json(w, http.StatusOK, map[string]interface{}{
		"scored_count": len(results),
		"results":      results,
	})
}

// ─── Applications ─────────────────────────────────────────────────────────

func (s *Server) handleCreateApplication(w http.ResponseWriter, r *http.Request) {
	var req CreateApplicationRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.badRequest(w, "Invalid request body")
		return
	}
	if req.JobID == "" || req.UserID == "" {
		s.badRequest(w, "job_id and user_id are required")
		return
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[req.UserID]; !ok {
		s.notFound(w)
		return
	}
	if _, ok := s.jobs[req.JobID]; !ok {
		s.notFound(w)
		return
	}
	for _, app := range s.apps {
		if app.JobID == req.JobID && app.UserID == req.UserID {
			s.badRequest(w, "Application already exists for this job and user")
			return
		}
	}

	nowStr := now()
	app := &Application{
		ID:        uuid.New().String(),
		JobID:     req.JobID,
		UserID:    req.UserID,
		Status:    "drafting",
		CreatedAt: nowStr,
		UpdatedAt: nowStr,
	}
	s.apps[app.ID] = app
	s.json(w, http.StatusCreated, app)
}

func (s *Server) handleApplicationByID(w http.ResponseWriter, r *http.Request) {
	path := strings.TrimPrefix(r.URL.Path, "/v1/applications/")
	parts := strings.SplitN(path, "/", 2)
	id := parts[0]
	if id == "" {
		s.notFound(w)
		return
	}

	switch r.Method {
	case http.MethodGet:
		s.mu.RLock()
		app, ok := s.apps[id]
		s.mu.RUnlock()
		if !ok {
			s.notFound(w)
			return
		}
		s.json(w, http.StatusOK, app)

	case http.MethodPatch:
		if len(parts) > 1 && parts[1] == "status" {
			var req UpdateApplicationStatusRequest
			if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
				s.badRequest(w, "Invalid request body")
				return
			}
			if !isValidAppStatus(req.Status) {
				s.badRequest(w, "Invalid status value")
				return
			}
			s.mu.Lock()
			app, ok := s.apps[id]
			if !ok {
				s.mu.Unlock()
				s.notFound(w)
				return
			}
			app.Status = req.Status
			if req.Status == "submitted" {
				app.AppliedAt = now()
			}
			app.UpdatedAt = now()
			s.mu.Unlock()
			s.json(w, http.StatusOK, app)
			return
		}
		s.notFound(w)

	default:
		s.methodNotAllowed(w)
	}
}

func (s *Server) handleListApplications(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	status := r.URL.Query().Get("status")
	limit, offset := 20, 0

	if l := r.URL.Query().Get("limit"); l != "" {
		fmt.Sscanf(l, "%d", &limit)
	}
	if limit > 100 {
		limit = 100
	}
	if o := r.URL.Query().Get("offset"); o != "" {
		fmt.Sscanf(o, "%d", &offset)
	}
	if userID == "" {
		s.badRequest(w, "user_id is required")
		return
	}

	s.mu.RLock()
	var apps []*Application
	for _, app := range s.apps {
		if app.UserID != userID {
			continue
		}
		if status != "" && app.Status != status {
			continue
		}
		apps = append(apps, app)
	}
	total := len(apps)
	if offset >= len(apps) {
		apps = []*Application{}
	} else {
		end := offset + limit
		if end > len(apps) {
			end = len(apps)
		}
		apps = apps[offset:end]
	}
	s.mu.RUnlock()

	s.json(w, http.StatusOK, map[string]interface{}{
		"applications": apps,
		"total":        total,
	})
}

// ─── Dashboard ─────────────────────────────────────────────────────────────

func (s *Server) handleDashboard(w http.ResponseWriter, r *http.Request) {
	userID := strings.TrimPrefix(r.URL.Path, "/v1/dashboard/")
	if userID == "" {
		s.notFound(w)
		return
	}

	s.mu.RLock()
	user, ok := s.users[userID]
	if !ok {
		s.mu.RUnlock()
		s.notFound(w)
		return
	}

	var jobs []*Job
	for _, job := range s.jobs {
		if job.UserID == userID {
			jobs = append(jobs, job)
		}
	}
	var apps []*Application
	for _, app := range s.apps {
		if app.UserID == userID {
			apps = append(apps, app)
		}
	}
	pipeline := make(map[string]int)
	for _, app := range apps {
		pipeline[app.Status]++
	}

	type scoredJob struct {
		job *Job
		fs  float64
	}
	var ranked []scoredJob
	for _, job := range jobs {
		fs := 0.0
		if job.FitScore != nil {
			fs = *job.FitScore
		}
		ranked = append(ranked, scoredJob{job, fs})
	}
	sort.Slice(ranked, func(i, j int) bool { return ranked[i].fs > ranked[j].fs })
	topJobs := make([]*Job, 0, 3)
	for i := 0; i < 3 && i < len(ranked); i++ {
		topJobs = append(topJobs, ranked[i].job)
	}

	var avgFS float64
	if len(jobs) > 0 {
		for _, job := range jobs {
			if job.FitScore != nil {
				avgFS += *job.FitScore
			}
		}
		avgFS /= float64(len(jobs))
	}

	type appWithJob struct {
		App *Application `json:"application"`
		Job *Job          `json:"job,omitempty"`
	}
	var recentApps []appWithJob
	sortedApps := make([]*Application, len(apps))
	copy(sortedApps, apps)
	sort.Slice(sortedApps, func(i, j int) bool { return sortedApps[i].UpdatedAt > sortedApps[j].UpdatedAt })
	for i := 0; i < 5 && i < len(sortedApps); i++ {
		var jobPtr *Job
		if job, ok := s.jobs[sortedApps[i].JobID]; ok {
			jobPtr = job
		}
		recentApps = append(recentApps, appWithJob{App: sortedApps[i], Job: jobPtr})
	}
	s.mu.RUnlock()

	s.json(w, http.StatusOK, map[string]interface{}{
		"total_jobs":          len(jobs),
		"new_jobs":            pipeline["new"],
		"interested_jobs":     pipeline["interested"],
		"applied_jobs":        pipeline["applied"],
		"interviewing_jobs":   pipeline["interviewing"],
		"offered_jobs":        pipeline["offered"],
		"avg_fit_score":       avgFS,
		"top_jobs":            topJobs,
		"recent_applications": recentApps,
		"pipeline_counts": map[string]int{
			"drafting":            pipeline["drafting"],
			"submitted":           pipeline["submitted"],
			"screening":           pipeline["screening"],
			"interview_scheduled": pipeline["interview_scheduled"],
			"interviewing":        pipeline["interviewing"],
			"offer":               pipeline["offer"],
			"rejected":            pipeline["rejected"],
			"withdrawn":           pipeline["withdrawn"],
		},
		"user": user,
	})
}

