func (s *Server) handlePersona(w http.ResponseWriter, r *http.Request) {
	userID := strings.TrimPrefix(r.URL.Path, "/v1/persona/")
	if userID == "" {
		s.notFound(w)
		return
	}

	s.mu.RLock()
	user, ok := s.users[userID]
	s.mu.RUnlock()
	if !ok {
		s.notFound(w)
		return
	}

	persona := user.Persona
	if persona == "" {
		persona = classifyPersona(CreateUserRequest{
			Skills:              user.Skills,
			IndustryPreferences: user.IndustryPreferences,
		})
	}

	traits := []Trait{
		{Name: "Openness", Value: 78},
		{Name: "Conscientiousness", Value: 85},
		{Name: "Extraversion", Value: 62},
		{Name: "Agreeableness", Value: 71},
		{Name: "Neuroticism (inverted)", Value: 66},
	}

	bestRoles := []string{}
	switch persona {
	case "Startup/Fixer":
		bestRoles = []string{"Chief AI Officer", "VP AI Strategy", "AI Product Lead", "Director of AI"}
	case "Technical":
		bestRoles = []string{"Principal AI Engineer", "Staff ML Engineer", "AI Architecture Lead", "CTO"}
	case "Management":
		bestRoles = []string{"VP Engineering", "Director of Product", "Chief People Officer", "SVP Operations"}
	case "Sales":
		bestRoles = []string{"VP Sales AI", "Chief Revenue Officer", "Director of Growth", "Head of Enterprise"}
	default:
		bestRoles = []string{"Senior Director", "VP Strategy", "Head of Operations", "Chief of Staff"}
	}

	s.json(w, http.StatusOK, Persona{
		Persona: persona,
		Traits:  traits,
		BestFit: bestRoles,
	})
}

// ─── Main ─────────────────────────────────────────────────────────────────

func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	server := NewServer()

	// Serve frontend static files (V20 version)
	frontendDir := filepath.Join(filepath.Dir(os.Args[0]), "..", "frontend")
	if _, err := os.Stat(frontendDir); os.IsNotExist(err) {
		// Try relative to working directory
		frontendDir = "frontend"
	}

	fs := http.FileServer(http.Dir(frontendDir))
	server.mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		// Don't intercept API or health routes
		if strings.HasPrefix(r.URL.Path, "/v1/") || r.URL.Path == "/health" {
			server.ServeHTTP(w, r)
			return
		}
		// Serve V20 static files — map root routes to V20 pages
		path := r.URL.Path
		switch path {
		case "/":
			path = "/index-v20.html"
		case "/assessment", "/assessment.html":
			path = "/assessment-v20.html"
		case "/probability", "/dashboard", "/dashboard.html":
			path = "/probability-v20.html"
		case "/coach", "/coach.html":
			path = "/coach-v20.html"
		case "/applications", "/applications.html", "/journey", "/tracker":
			path = "/applications-v20.html"
		}
		// Set correct content types
		ext := filepath.Ext(path)
		switch ext {
		case ".html":
			w.Header().Set("Content-Type", "text/html; charset=utf-8")
		case ".css":
			w.Header().Set("Content-Type", "text/css; charset=utf-8")
		case ".js":
			w.Header().Set("Content-Type", "application/javascript; charset=utf-8")
		case ".svg":
			w.Header().Set("Content-Type", "image/svg+xml")
		case ".png":
			w.Header().Set("Content-Type", "image/png")
		case ".ico":
			w.Header().Set("Content-Type", "image/x-icon")
		}
		fs.ServeHTTP(w, r)
	})

	addr := ":" + port
	log.Printf("Signal server starting on %s", addr)
	log.Printf("Frontend served from %s", frontendDir)
	log.Fatal(http.ListenAndServe(addr, server))
}
